// EXPECT-ESLINT: exhaustive-deps WARN (deps array [q] missing state var 'n')
import { useEffect, useState } from 'react';

export function Counter({ q }: { q: string }) {
  const [n, setN] = useState(0);
  useEffect(() => {
    console.log(q, n);
  }, [q]);
  return <button onClick={() => setN(n + 1)}>{n}</button>;
}

// EXPECT-ESLINT: rules-of-hooks ERROR (hook called after a conditional early return)
import { useState } from 'react';

export function EarlyReturn({ ready }: { ready: boolean }) {
  if (!ready) return null;
  const [v] = useState(0);
  return <p>{v}</p>;
}

// EXPECT-ESLINT: rules-of-hooks ERROR (hook in class component method)
import * as React from 'react';
import { useState } from 'react';

export class Legacy extends React.Component {
  render() {
    const [v] = useState(0);
    return <p>{v}</p>;
  }
}

// EXPECT-ESLINT: rules-of-hooks ERROR (hook inside an event-handler callback)
import { useState } from 'react';

export function Btn() {
  return (
    <button
      onClick={() => {
        const [c] = useState(0);
        console.log(c);
      }}
    >
      x
    </button>
  );
}

// EXPECT-ESLINT: rules-of-hooks ERROR (hook called in a loop)
import { useState } from 'react';

export function ForBad({ items }: { items: string[] }) {
  const out: string[] = [];
  for (let i = 0; i < items.length; i++) {
    const [v] = useState(items[i]);
    out.push(v);
  }
  return <p>{out.join(',')}</p>;
}

// EXPECT-ESLINT: rules-of-hooks ERROR (hook called conditionally in if)
import { useState } from 'react';

export function IfBad({ flag }: { flag: boolean }) {
  if (flag) {
    const [a] = useState(1);
    return <p>{a}</p>;
  }
  return null;
}

// EXPECT-ESLINT: rules-of-hooks ERROR (hook called conditionally via && short-circuit)
import { useMemo } from 'react';

export function AndBad({ flag }: { flag: boolean }) {
  const v = flag && useMemo(() => 1, []);
  return <p>{v}</p>;
}

// EXPECT-ESLINT: rules-of-hooks ERROR (hook in plain lowercase function)
import { useState } from 'react';

export function loadData() {
  const [d] = useState<string | null>(null);
  return d;
}

// EXPECT-ESLINT: rules-of-hooks ERROR (hook called conditionally via ternary)
import { useMemo } from 'react';

export function TernaryBad({ flag }: { flag: boolean }) {
  const v = flag ? useMemo(() => 1, []) : 0;
  return <p>{v}</p>;
}

// EXPECT-ESLINT: rules-of-hooks ERROR (hook inside useEffect callback)
import { useEffect, useState } from 'react';

export function EffectNest() {
  useEffect(() => {
    const [x] = useState(0);
    console.log(x);
  }, []);
  return null;
}

// EXPECT-ESLINT: rules-of-hooks ERROR (hook inside useMemo callback)
import { useMemo, useState } from 'react';

export function MemoNest() {
  const v = useMemo(() => {
    const [x] = useState(1);
    return x;
  }, []);
  return <p>{v}</p>;
}

// EXPECT-ESLINT: rules-of-hooks ERROR (React.useState called conditionally)
import * as React from 'react';

export function NsHook({ flag }: { flag: boolean }) {
  if (flag) {
    const [v] = React.useState(0);
    return <p>{v}</p>;
  }
  return null;
}
